const incomingName = ($('Execute Workflow Trigger').first().json.triage?.extractedName || $('Execute Workflow Trigger').first().json.callerName || '').toLowerCase();
const incomingEmail = ($('Execute Workflow Trigger').first().json.triage?.extractedEmail || $('Execute Workflow Trigger').first().json.callerEmail || '').toLowerCase();

const contacts = $('Clio — Search contacts').first().json.data || [];
const matters = $('Clio — Search matters').first().json.data || [];

function tokenOverlap(a, b) {
  const ta = a.split(/\s+/);
  const tb = b.split(/\s+/);
  return ta.some(t => t.length > 2 && tb.some(s => s.includes(t) || t.includes(s)));
}

let conflictFound = false;
let conflictDetail = '';

for (const contact of contacts) {
  const name = (contact.name || '').toLowerCase();
  const emails = (contact.email_addresses || []).map(e => e.address.toLowerCase());
  const nameMatch = tokenOverlap(incomingName, name);
  const emailMatch = incomingEmail && emails.includes(incomingEmail);

  if (nameMatch || emailMatch) {
    for (const matter of matters) {
      const opps = (matter.opposing_parties || []).map(o => (o.name || '').toLowerCase());
      if (opps.some(o => tokenOverlap(o, name))) {
        conflictFound = true;
        conflictDetail = `"${contact.name}" appears as opposing party in matter #${matter.id}: ${matter.description}`;
        break;
      }
    }
  }
  if (conflictFound) break;
}

return [{ json: { conflictFound, conflictDetail, checkedName: incomingName, upstream: $('Execute Workflow Trigger').first().json } }];
